"use client";

export type { ToasterProps } from "./toast-container";
export { Toaster } from "./toast-container";
export type { Toast, ToastOptions, ToastPosition } from "./toast-store";
export { toast } from "./toast-store";
export type { ToastTone, ToastVariant } from "./toast-variants";

"use client";

import { lazy, Suspense } from "react";
import { cn } from "@/lib/utils";
import { CountdownBar } from "./countdown";
import type { ToastPosition, Toast as ToastType } from "./toast-store";
import {
  icons,
  positionToSide,
  type ToastTone,
  toastShellVariants,
  toastSlideInVariants,
  toastSlideOutVariants,
  toastToneBg,
  toastToneBorder,
  toastToneCornerBorder,
  toastToneText,
} from "./toast-variants";
import { useToastDismiss } from "./use-dismiss";

const LazySpinner = lazy(() => import("../spinner/spinner").then((m) => ({ default: m.Spinner })));

/** Props for toast. */
interface ToastProps extends ToastType {
  /** Placement position. */
  position: ToastPosition;
  onDismiss: (id: string) => void;
  onRemove: (id: string) => void;
  dismissing?: boolean;
}

// role="alert" implies aria-live="assertive"+aria-atomic="true"; role="status"
// implies aria-live="polite". Setting both is what WAI-ARIA recommends against,
// so we rely on the role to carry the live-region contract.
const TONE_ROLE: Record<ToastTone, "status" | "alert"> = {
  success: "status",
  error: "alert",
  warning: "status",
  info: "status",
  loading: "status",
};

/** Individual toast notification with position-aware animation. */
export function Toast(props: ToastProps) {
  const { id, tone, variant, dismissing, position, onRemove } = props;
  const { onAnimationEnd } = useToastDismiss(dismissing ?? false, id, onRemove);
  const side = positionToSide[position];
  const animation = dismissing ? toastSlideOutVariants({ side }) : toastSlideInVariants({ side });
  // HUD is informational by definition (single-line confirmation) — even an
  // error-tone HUD stays role="status" so it doesn't preempt screen-reader
  // output. Card/viewfinder/countdown use the tone mapping so error tones
  // still announce as alerts.
  const role = variant === "hud" ? "status" : TONE_ROLE[tone];
  const toneAccent = variant === "hud" || variant === "countdown" ? toastToneBorder({ tone }) : "";

  return (
    <div
      role={role}
      data-slot="toast"
      data-tone={tone}
      data-variant={variant}
      className={cn("pointer-events-auto", toastShellVariants({ variant }), toneAccent, animation)}
      onAnimationEnd={onAnimationEnd}
    >
      <ToastLayout {...props} />
    </div>
  );
}

function ToastLayout(props: ToastProps) {
  switch (props.variant) {
    case "hud":
      return <HudLayout {...props} />;
    case "viewfinder":
      return <ViewfinderLayout {...props} />;
    case "countdown":
      return <CountdownLayout {...props} />;
    default:
      return <CardLayout {...props} />;
  }
}

function ToneIcon({ tone }: { tone: ToastTone }) {
  if (tone === "loading") {
    return (
      <Suspense fallback={null}>
        <LazySpinner variant="braille" size="sm" gap="none" aria-hidden="true" />
      </Suspense>
    );
  }
  return icons[tone];
}

function CloseButton({
  id,
  title,
  dismissLabel,
  onDismiss,
}: {
  id: string;
  title: string;
  dismissLabel?: string;
  onDismiss: (id: string) => void;
}) {
  return (
    <button
      type="button"
      onClick={() => onDismiss(id)}
      className={cn(
        "min-h-6 min-w-6 p-1 flex items-center justify-center text-xs leading-none",
        "text-muted hover:text-foreground cursor-pointer",
        "focus-visible:outline-2 focus-visible:outline-ring focus-visible:outline-offset-2",
      )}
      aria-label={dismissLabel ?? `Dismiss: ${title}`}
    >
      ✕
    </button>
  );
}

function HudLayout({ tone, toneLabel, title, message }: ToastProps) {
  return (
    <>
      <span
        className={cn("inline-flex w-3 justify-center font-bold", toastToneText({ tone }))}
        aria-hidden="true"
      >
        <ToneIcon tone={tone} />
      </span>
      <span className="sr-only">{toneLabel ?? tone}:</span>
      <span className="font-bold text-foreground">{title}</span>
      {message && <span className="text-muted-foreground truncate">{message}</span>}
    </>
  );
}

function CardLayout({
  id,
  tone,
  toneLabel,
  title,
  message,
  action,
  dismissLabel,
  onDismiss,
}: ToastProps) {
  return (
    <>
      <span aria-hidden="true" className={cn("w-[3px] shrink-0", toastToneBg({ tone }))} />
      <div className="flex-1 min-w-0 px-3 pt-2.5 pb-3 grid grid-cols-[14px_1fr_auto] gap-x-2.5 gap-y-1 items-start">
        <span
          className={cn("font-bold leading-none mt-[3px]", toastToneText({ tone }))}
          aria-hidden="true"
        >
          <ToneIcon tone={tone} />
        </span>
        <span className="sr-only">{toneLabel ?? tone}:</span>
        <div className="flex flex-col gap-1 min-w-0">
          <span className="text-sm font-bold text-foreground">{title}</span>
          {message && (
            <span className="text-xs text-muted-foreground leading-relaxed">{message}</span>
          )}
          {action && (
            <span data-slot="toast-action" className="mt-1 text-xs">
              {action}
            </span>
          )}
        </div>
        <CloseButton id={id} title={title} dismissLabel={dismissLabel} onDismiss={onDismiss} />
      </div>
    </>
  );
}

function ViewfinderLayout({
  id,
  tone,
  toneLabel,
  title,
  message,
  dismissLabel,
  onDismiss,
}: ToastProps) {
  return (
    <>
      <ViewfinderCorners tone={tone} />
      <div className="flex items-center justify-between mb-2 gap-2">
        <span className="inline-flex items-stretch gap-2.5 text-xs font-bold tracking-wider uppercase text-foreground">
          <span
            aria-hidden="true"
            className={cn("inline-block w-[3px] min-h-3.5", toastToneBg({ tone }))}
          />
          <span className="sr-only">{toneLabel ?? tone}:</span>
          {title}
        </span>
        <CloseButton id={id} title={title} dismissLabel={dismissLabel} onDismiss={onDismiss} />
      </div>
      {message && <div className="text-sm text-foreground/90">{message}</div>}
    </>
  );
}

function ViewfinderCorners({ tone }: { tone: ToastTone }) {
  const colorClass = toastToneCornerBorder({ tone });
  return (
    <span aria-hidden="true" data-slot="toast-corners" className="pointer-events-none">
      <span
        className={cn(
          "absolute -top-px -left-px w-3.5 h-3.5 border-0 border-t-2 border-l-2",
          colorClass,
        )}
      />
      <span
        className={cn(
          "absolute -top-px -right-px w-3.5 h-3.5 border-0 border-t-2 border-r-2",
          colorClass,
        )}
      />
      <span
        className={cn(
          "absolute -bottom-px -left-px w-3.5 h-3.5 border-0 border-b-2 border-l-2",
          colorClass,
        )}
      />
      <span
        className={cn(
          "absolute -bottom-px -right-px w-3.5 h-3.5 border-0 border-b-2 border-r-2",
          colorClass,
        )}
      />
    </span>
  );
}

function CountdownLayout(props: ToastProps) {
  return (
    <>
      <div className="flex">
        <CardLayout {...props} />
      </div>
      <CountdownBar id={props.id} tone={props.tone} />
    </>
  );
}

"use client";

import { isEditableElement } from "@/hooks/utils/element-guards";
import { type FocusEvent, useEffect, useRef, useState } from "react";
import { createTopLayerStack, useTopLayerPosition } from "@/lib/top-layer-stack";
import { cn } from "@/lib/utils";
import { Toast } from "./toast";
import {
  dismiss,
  pause,
  remove,
  resume,
  type Toast as ToastData,
  type ToastPosition,
  useToastStore,
} from "./toast-store";
import { toastPositionVariants } from "./toast-variants";
import { useToastContainer } from "./use-container";

function handleBlur(e: FocusEvent<HTMLDivElement>) {
  const View = e.currentTarget.ownerDocument.defaultView;
  if (
    !View ||
    !(e.relatedTarget instanceof View.Node) ||
    !e.currentTarget.contains(e.relatedTarget)
  ) {
    resume("focus");
  }
}

function supportsPopover(ownerDocument: Document): boolean {
  const HTMLElementCtor = ownerDocument.defaultView?.HTMLElement;
  return Boolean(HTMLElementCtor && "popover" in HTMLElementCtor.prototype);
}

function announcementText(toast: ToastData): string {
  return toast.message ? `${toast.title}, ${toast.message}` : toast.title;
}

const ANNOUNCEMENT_REMOVE_DELAY = 1000;

interface ToastAnnouncement {
  key: string;
  text: string;
}

const toasterStack = createTopLayerStack();

/** Props for toaster. */
export interface ToasterProps {
  /** Corner where toasts stack. Drives positioning classes and slide-in direction. */
  position?: ToastPosition;
  /**
   * Key that moves DOM focus to the toast region so keyboard users can reach action/close
   * buttons before a timed toast disappears. Matched against `KeyboardEvent.key` and ignored
   * while an editable element has focus. Defaults to F8, the Radix viewport hotkey.
   */
  hotkey?: string;
}

/** Fixed-position container, subscribes to toast store. */
export function Toaster({ position = "bottom-right", hotkey = "F8" }: ToasterProps) {
  const { toasts, dismissingIds } = useToastStore();
  const containerRef = useRef<HTMLDivElement | null>(null);
  const isTopToaster = useTopLayerPosition(toasterStack, containerRef, true);

  const visibleToasts = isTopToaster ? toasts : [];
  useToastContainer(visibleToasts, dismissingIds, containerRef, isTopToaster);
  const hasToasts = visibleToasts.length > 0;

  // Persistent visually-hidden polite live region (Radix announcer pattern):
  // exists before its first announcement, then each new non-error toast's text
  // is written in. Error toasts already announce via role="alert"; routing them
  // here too would double-announce.
  const [announcements, setAnnouncements] = useState<ToastAnnouncement[]>([]);
  const announcedIds = useRef<Set<string>>(new Set());
  const announcementSequence = useRef(0);
  const announcementTimers = useRef(new Map<string, ReturnType<typeof setTimeout>>());
  const wasTopToaster = useRef(false);

  useEffect(() => {
    return () => {
      for (const timer of announcementTimers.current.values()) clearTimeout(timer);
      announcementTimers.current.clear();
    };
  }, []);

  useEffect(() => {
    if (!isTopToaster) {
      wasTopToaster.current = false;
      announcedIds.current = new Set(toasts.map((t) => t.id));
      for (const timer of announcementTimers.current.values()) clearTimeout(timer);
      announcementTimers.current.clear();
      setAnnouncements((current) => (current.length > 0 ? [] : current));
      return;
    }

    const currentIds = new Set(toasts.map((t) => t.id));
    if (!wasTopToaster.current) {
      wasTopToaster.current = true;
      announcedIds.current = currentIds;
      return;
    }

    const nextAnnouncements: ToastAnnouncement[] = [];
    for (const toast of toasts) {
      if (toast.tone === "error" || announcedIds.current.has(toast.id)) continue;
      const key = `${toast.id}:${announcementSequence.current}`;
      announcementSequence.current += 1;
      nextAnnouncements.push({ key, text: announcementText(toast) });
    }
    announcedIds.current = currentIds;
    if (nextAnnouncements.length === 0) return;

    setAnnouncements((current) => [...current, ...nextAnnouncements]);
    for (const announcement of nextAnnouncements) {
      const timer = setTimeout(() => {
        announcementTimers.current.delete(announcement.key);
        setAnnouncements((current) => current.filter((item) => item.key !== announcement.key));
      }, ANNOUNCEMENT_REMOVE_DELAY);
      announcementTimers.current.set(announcement.key, timer);
    }
  }, [isTopToaster, toasts]);

  useEffect(() => {
    if (!isTopToaster) return;
    const element = containerRef.current;
    const ownerDocument = element?.ownerDocument;
    if (!ownerDocument) return;
    const onKeyDown = (event: KeyboardEvent) => {
      if (event.defaultPrevented) return;
      if (event.key !== hotkey) return;
      // Shadow DOM retargets event.target to the host on the document listener;
      // composedPath()[0] is the real inner target so a focused input/select in
      // an open shadow tree still defers the shortcut.
      const target = event.composedPath()[0] ?? event.target;
      if (isEditableElement(target)) return;
      const region = containerRef.current;
      if (!region) return;
      event.preventDefault();
      region.focus();
    };
    ownerDocument.addEventListener("keydown", onKeyDown);
    return () => ownerDocument.removeEventListener("keydown", onKeyDown);
  }, [hotkey, isTopToaster]);

  // <dialog>.showModal() raises the dialog into the browser top-layer, which
  // z-index cannot beat; opting the container into the Popover API puts the
  // toast in the same top-layer. Set imperatively (not in JSX) so browsers/tests
  // without Popover support keep the plain fixed+z-index path instead of being
  // hidden by the UA stylesheet's display:none.
  //
  // showModal() appends a dialog ABOVE a pre-existing manual popover (which is
  // exempt from its hide-all), so a MutationObserver on dialog[open] re-runs
  // hidePopover/showPopover to rejoin the top-layer above the dialog.
  useEffect(() => {
    if (!hasToasts) return;
    const element = containerRef.current;
    const view = element?.ownerDocument.defaultView;
    if (!element || !view || !supportsPopover(element.ownerDocument)) return;
    if (element.popover !== "manual") element.popover = "manual";

    const promote = (): boolean => {
      if (element.matches(":popover-open")) element.hidePopover();
      try {
        element.showPopover();
        return true;
      } catch {
        element.removeAttribute("popover");
        return false;
      }
    };

    if (!promote()) return;

    const observer = new view.MutationObserver(promote);
    observer.observe(element.ownerDocument.documentElement, {
      attributes: true,
      attributeFilter: ["open"],
      subtree: true,
    });

    return () => {
      observer.disconnect();
      if (element.matches(":popover-open")) element.hidePopover();
      element.removeAttribute("popover");
    };
  }, [hasToasts]);

  if (!isTopToaster)
    // biome-ignore lint/a11y/useSemanticElements: matches the active toast container element while preserving the hidden placeholder for stack registration.
    return <div ref={containerRef} role="region" aria-label="Notifications" hidden />;

  return (
    // biome-ignore lint/a11y/useSemanticElements: role="region" with aria-label is the standard toast live-region container; swapping to <section> would change the styling element and add a page landmark.
    <div
      ref={containerRef}
      role="region"
      aria-label="Notifications"
      tabIndex={-1}
      onMouseEnter={() => pause("hover")}
      onMouseLeave={() => resume("hover")}
      onFocus={() => pause("focus")}
      onBlur={handleBlur}
      className={cn(
        // Override the UA [popover] stylesheet (inset:0, margin:auto, fit-content,
        // border/padding/background) so corner positioning and the transparent
        // backdrop survive when popover mode activates.
        "fixed z-[var(--z-toast)] flex gap-2 pointer-events-none outline-none",
        "[&[popover]]:m-0 [&[popover]]:p-0 [&[popover]]:max-w-none [&[popover]]:max-h-none [&[popover]]:w-auto [&[popover]]:h-auto",
        "[&[popover]]:bg-transparent [&[popover]]:border-0 [&[popover]]:overflow-visible",
        toastPositionVariants({ position }),
      )}
    >
      <span data-slot="toast-announcer" className="sr-only" aria-live="polite">
        {announcements.map((announcement) => (
          <span key={announcement.key} data-slot="toast-announcement">
            {announcement.text}
          </span>
        ))}
      </span>
      {visibleToasts.map((t) => (
        <Toast
          key={t.id}
          {...t}
          position={position}
          onDismiss={dismiss}
          onRemove={remove}
          dismissing={dismissingIds.has(t.id)}
        />
      ))}
    </div>
  );
}

import { cva } from "class-variance-authority";

/** Allowed toast position values. */
export type ToastPosition =
  | "top-left"
  | "top-center"
  | "top-right"
  | "bottom-left"
  | "bottom-center"
  | "bottom-right";

/** Allowed toast tone values. */
export type ToastTone = "success" | "error" | "warning" | "info" | "loading";
/** Allowed toast variant values. */
export type ToastVariant = "hud" | "card" | "viewfinder" | "countdown";

export const toastToneBorder = cva("", {
  variants: {
    tone: {
      success: "border-success-border",
      error: "border-error-border",
      warning: "border-warning-border",
      info: "border-info-border",
      loading: "border-info-border",
    },
  },
  defaultVariants: { tone: "info" },
});

export const toastToneText = cva("", {
  variants: {
    tone: {
      success: "text-success-text",
      error: "text-error-text",
      warning: "text-warning-text",
      info: "text-info-text",
      loading: "text-info-text",
    },
  },
  defaultVariants: { tone: "info" },
});

export const toastToneBg = cva("", {
  variants: {
    tone: {
      success: "bg-success-text",
      error: "bg-error-text",
      warning: "bg-warning-text",
      info: "bg-info-text",
      loading: "bg-info-text",
    },
  },
  defaultVariants: { tone: "info" },
});

export const toastToneCornerBorder = cva("", {
  variants: {
    tone: {
      success: "border-success-text",
      error: "border-error-text",
      warning: "border-warning-text",
      info: "border-info-text",
      loading: "border-info-text",
    },
  },
  defaultVariants: { tone: "info" },
});

/** Class variants for toast shell. */
export const toastShellVariants = cva("font-mono", {
  variants: {
    variant: {
      hud: "inline-flex items-center gap-2.5 max-w-[360px] px-3.5 py-2 text-xs bg-[color:var(--surface-1)] border",
      card: "flex bg-[color:var(--surface-1)] border border-border/40",
      viewfinder: "relative px-4 py-3 bg-background border border-border/40",
      countdown: "relative flex flex-col bg-[color:var(--surface-1)] border",
    },
  },
  defaultVariants: { variant: "card" },
});

export const icons: Record<Exclude<ToastTone, "loading">, string> = {
  success: "✓",
  error: "✕",
  warning: "!",
  info: "i",
};

export type ToastSide = "left" | "right" | "top" | "bottom";

/** Class variants for toast slide in. */
export const toastSlideInVariants = cva("motion-reduce:animate-[fade-in_0.15s_ease-out]", {
  variants: {
    side: {
      left: "motion-safe:animate-slide-in-left",
      right: "motion-safe:animate-slide-in-right",
      top: "motion-safe:animate-slide-in-top",
      bottom: "motion-safe:animate-slide-in-bottom",
    },
  },
  defaultVariants: { side: "right" },
});

/** Class variants for toast slide out. */
export const toastSlideOutVariants = cva(
  "motion-reduce:animate-[fade-out_0.15s_ease-in_forwards]",
  {
    variants: {
      side: {
        left: "motion-safe:animate-slide-out-left",
        right: "motion-safe:animate-slide-out-right",
        top: "motion-safe:animate-slide-out-top",
        bottom: "motion-safe:animate-slide-out-bottom",
      },
    },
    defaultVariants: { side: "right" },
  },
);

export const positionToSide: Record<ToastPosition, ToastSide> = {
  "top-left": "left",
  "top-center": "top",
  "top-right": "right",
  "bottom-left": "left",
  "bottom-center": "bottom",
  "bottom-right": "right",
};

/** Class variants for toast position. */
export const toastPositionVariants = cva("", {
  variants: {
    position: {
      "top-left":
        "flex-col top-[max(1rem,env(safe-area-inset-top))] left-[max(1rem,env(safe-area-inset-left))] right-[max(1rem,env(safe-area-inset-right))] sm:right-auto sm:left-[max(2rem,env(safe-area-inset-left))] sm:w-80",
      "top-center":
        "flex-col top-[max(1rem,env(safe-area-inset-top))] left-[max(1rem,env(safe-area-inset-left))] right-[max(1rem,env(safe-area-inset-right))] sm:inset-x-0 sm:mx-auto sm:w-80",
      "top-right":
        "flex-col top-[max(1rem,env(safe-area-inset-top))] left-[max(1rem,env(safe-area-inset-left))] right-[max(1rem,env(safe-area-inset-right))] sm:left-auto sm:right-[max(2rem,env(safe-area-inset-right))] sm:w-80",
      "bottom-left":
        "flex-col-reverse bottom-[max(1rem,env(safe-area-inset-bottom))] left-[max(1rem,env(safe-area-inset-left))] right-[max(1rem,env(safe-area-inset-right))] pointer-coarse:top-[max(1rem,env(safe-area-inset-top))] pointer-coarse:bottom-auto pointer-coarse:flex-col sm:right-auto sm:left-[max(2rem,env(safe-area-inset-left))] sm:w-80",
      "bottom-center":
        "flex-col-reverse bottom-[max(1rem,env(safe-area-inset-bottom))] left-[max(1rem,env(safe-area-inset-left))] right-[max(1rem,env(safe-area-inset-right))] pointer-coarse:top-[max(1rem,env(safe-area-inset-top))] pointer-coarse:bottom-auto pointer-coarse:flex-col sm:inset-x-0 sm:mx-auto sm:w-80",
      "bottom-right":
        "flex-col-reverse bottom-[max(1rem,env(safe-area-inset-bottom))] left-[max(1rem,env(safe-area-inset-left))] right-[max(1rem,env(safe-area-inset-right))] pointer-coarse:top-[max(1rem,env(safe-area-inset-top))] pointer-coarse:bottom-auto pointer-coarse:flex-col sm:left-auto sm:right-[max(2rem,env(safe-area-inset-right))] sm:w-80",
    },
  },
  defaultVariants: { position: "bottom-right" },
});

"use client";

import { type ReactNode, useSyncExternalStore } from "react";
import { createToastTimers, type ToastTimerSnapshot, type ToastTimers } from "./toast-timers";
import type { ToastTone, ToastVariant } from "./toast-variants";

export type { ToastTimerSnapshot } from "./toast-timers";
export type { ToastPosition } from "./toast-variants";

export interface Toast {
  /** ID applied to the rendered element. */
  id: string;
  /** Visual tone. */
  tone: ToastTone;
  /** Visual style variant. */
  variant: ToastVariant;
  /** Title content. */
  title: string;
  /** Message content. */
  message?: string;
  /** Duration in milliseconds. */
  duration?: number;
  /** Action rendered with the item. */
  action?: ReactNode;
  /** Accessible name for the dismiss button. Defaults to `Dismiss: ${title}`. */
  dismissLabel?: string;
  /** Screen-reader tone word announced before the title. Defaults to the tone name. */
  toneLabel?: string;
}

/** Options for toast. */
export interface ToastOptions {
  /** Title content. */
  title: string;
  /** Visual tone. */
  tone?: ToastTone;
  /** Visual style variant. */
  variant?: ToastVariant;
  /** Message content. */
  message?: string;
  /** Duration in milliseconds. */
  duration?: number;
  /** Action rendered with the item. */
  action?: ReactNode;
  /** ID applied to the rendered element. */
  id?: string;
  /** Accessible label for dismiss. */
  dismissLabel?: string;
  /** Accessible label for tone. */
  toneLabel?: string;
}

const DEFAULT_DURATION = 5000;
const MAX_TOASTS = 5;

export type ToastPauseCause = "hover" | "focus" | "document-hidden";

interface StoreState {
  toasts: Toast[];
  dismissingIds: Set<string>;
  pauseCauses: Set<ToastPauseCause>;
  paused: boolean;
  timerVersion: number;
}

const INITIAL_STATE: StoreState = {
  toasts: [],
  dismissingIds: new Set(),
  pauseCauses: new Set(),
  paused: false,
  timerVersion: 0,
};

let state: StoreState = INITIAL_STATE;
const listeners = new Set<() => void>();
let toastTimers: ToastTimers | undefined;
let fallbackToastId = 0;

function timers() {
  if (!toastTimers) {
    toastTimers = createToastTimers({ onElapsed: (id) => dismiss(id) });
  }
  return toastTimers;
}

function emit() {
  for (const listener of listeners) listener();
}

function clearTimer(id: string) {
  timers().clear(id);
}

function subscribe(listener: () => void) {
  listeners.add(listener);
  return () => listeners.delete(listener);
}

function getSnapshot(): StoreState {
  return state;
}

function getServerSnapshot(): StoreState {
  return INITIAL_STATE;
}

function scheduleAutoDismiss(id: string, tone: ToastTone, duration?: number) {
  if ((tone === "error" || tone === "loading") && duration === undefined) return;
  const resolved = duration ?? DEFAULT_DURATION;
  if (!Number.isFinite(resolved) || resolved <= 0) return;
  timers().schedule(id, resolved, state.paused);
}

function isEvictable(t: Toast): boolean {
  // Persistent toasts (with actions and no explicit duration) and
  // error/loading toasts without duration should not be evicted before
  // transient toasts (WCAG 2.2.1 — enough time).
  if (t.action && t.duration === undefined) return false;
  if ((t.tone === "error" || t.tone === "loading") && t.duration === undefined) return false;
  return true;
}

function resolveNextToasts(current: Toast[], incoming: Toast): Toast[] {
  const existingIdx = current.findIndex((t) => t.id === incoming.id);
  if (existingIdx >= 0) return current.map((t) => (t.id === incoming.id ? incoming : t));

  if (current.length < MAX_TOASTS) return [...current, incoming];

  const evicted: Toast[] = [];
  const remaining = [...current];

  while (remaining.length >= MAX_TOASTS) {
    const transientIndex = remaining.findIndex(isEvictable);
    const evictionIndex = transientIndex >= 0 ? transientIndex : 0;
    const [removed] = remaining.splice(evictionIndex, 1);
    if (removed) evicted.push(removed);
  }

  for (const t of evicted) clearTimer(t.id);
  return [...remaining, incoming];
}

function createToastId(): string {
  const randomUUID = globalThis.crypto?.randomUUID;
  if (typeof randomUUID === "function") return randomUUID.call(globalThis.crypto);

  fallbackToastId += 1;
  return `toast-${Date.now().toString(36)}-${fallbackToastId.toString(36)}`;
}

function create(options: ToastOptions): string {
  const id = options.id ?? createToastId();
  const tone = options.tone ?? "info";
  const variant = options.variant ?? "card";

  const effectiveAction = variant === "hud" ? undefined : options.action;
  const newToast: Toast = {
    id,
    tone,
    variant,
    title: options.title,
    message: options.message,
    duration: options.duration,
    action: effectiveAction,
    dismissLabel: options.dismissLabel,
    toneLabel: options.toneLabel,
  };

  clearTimer(id);
  const nextDismissing = new Set(state.dismissingIds);
  nextDismissing.delete(id);
  // Persist indefinitely only when there's a real, rendered action (WCAG 2.2.1).
  // HUD drops the action, so a HUD with an "action" still auto-dismisses.
  if (!effectiveAction || options.duration !== undefined) {
    scheduleAutoDismiss(id, tone, options.duration);
  }

  const nextToasts = resolveNextToasts(state.toasts, newToast);
  const nextIds = new Set(nextToasts.map((t) => t.id));
  for (const dismissId of nextDismissing) {
    if (!nextIds.has(dismissId)) nextDismissing.delete(dismissId);
  }

  state = {
    ...state,
    toasts: nextToasts,
    dismissingIds: nextDismissing,
    timerVersion: timers().version,
  };
  emit();
  return id;
}

export function dismiss(id?: string) {
  if (id) {
    state = {
      ...state,
      dismissingIds: new Set(state.dismissingIds).add(id),
    };
  } else {
    state = { ...state, dismissingIds: new Set(state.toasts.map((t) => t.id)) };
  }
  emit();
}

export function remove(id: string) {
  clearTimer(id);
  const nextDismissing = new Set(state.dismissingIds);
  nextDismissing.delete(id);
  const nextToasts = state.toasts.filter((t) => t.id !== id);
  let pauseCauses = state.pauseCauses;
  let paused = state.paused;
  if (nextToasts.length === 0) {
    if (toastTimers) toastTimers.resume();
    toastTimers = undefined;
    pauseCauses = new Set();
    paused = false;
  }
  state = {
    ...state,
    toasts: nextToasts,
    dismissingIds: nextDismissing,
    pauseCauses,
    paused,
    timerVersion: nextToasts.length === 0 ? 0 : timers().version,
  };
  emit();
}

export function pause(cause: ToastPauseCause) {
  if (state.pauseCauses.has(cause)) return;
  const pauseCauses = new Set(state.pauseCauses).add(cause);
  if (state.paused) {
    state = { ...state, pauseCauses, paused: true };
    emit();
    return;
  }
  timers().pause();
  state = {
    ...state,
    pauseCauses,
    paused: true,
    timerVersion: timers().version,
  };
  emit();
}

export function resume(cause: ToastPauseCause) {
  if (!state.pauseCauses.has(cause)) return;
  const pauseCauses = new Set(state.pauseCauses);
  pauseCauses.delete(cause);
  if (pauseCauses.size > 0) {
    state = { ...state, pauseCauses, paused: true };
    emit();
    return;
  }
  timers().resume();
  state = {
    ...state,
    pauseCauses,
    paused: false,
    timerVersion: timers().version,
  };
  emit();
}

export function getTimerSnapshot(id: string): ToastTimerSnapshot | null {
  return timers().snapshot(id);
}

type ToneMethod = (title: string, options?: Omit<ToastOptions, "tone" | "title">) => string;

interface ToastFn extends Record<ToastTone, ToneMethod> {
  (title: string, options?: Omit<ToastOptions, "title">): string;
  dismiss: (id?: string) => void;
  promise: <T>(
    promise: Promise<T>,
    options: {
      loading: string;
      success: string | ((data: T) => string);
      error: string | ((err: unknown) => string);
    },
  ) => Promise<T>;
}

function toneMethod(tone: ToastTone): ToneMethod {
  return (title, options) => create({ ...options, title, tone });
}

function promiseToast<T>(
  promise: Promise<T>,
  options: {
    loading: string;
    success: string | ((data: T) => string);
    error: string | ((err: unknown) => string);
  },
): Promise<T> {
  const id = create({ title: options.loading, tone: "loading" });

  return promise.then(
    (data) => {
      const title = typeof options.success === "function" ? options.success(data) : options.success;
      create({ id, title, tone: "success" });
      return data;
    },
    (err) => {
      const title = typeof options.error === "function" ? options.error(err) : options.error;
      create({ id, title, tone: "error" });
      throw err;
    },
  );
}

export const toast: ToastFn = Object.assign(
  (title: string, options?: Omit<ToastOptions, "title">) => create({ ...options, title }),
  {
    success: toneMethod("success"),
    error: toneMethod("error"),
    warning: toneMethod("warning"),
    info: toneMethod("info"),
    loading: toneMethod("loading"),
    dismiss,
    promise: promiseToast,
  },
);

/** Provides toast store behavior. */
export function useToastStore(): StoreState {
  return useSyncExternalStore(subscribe, getSnapshot, getServerSnapshot);
}

export interface ToastTimerSnapshot {
  /** Duration in milliseconds. */
  duration: number;
  /** Remaining time in milliseconds. */
  remaining: number;
  /** Timestamp when the timer started. */
  startedAt: number;
}

type TimeoutHandle = ReturnType<typeof globalThis.setTimeout>;
type SetTimeoutFn = (fn: () => void, ms: number) => TimeoutHandle;
type ClearTimeoutFn = (handle: TimeoutHandle) => void;

interface TimerEntry {
  timeout: TimeoutHandle | undefined;
  startedAt: number;
  remaining: number;
  duration: number;
}

export interface ToastTimers {
  schedule(id: string, duration: number, deferTimeout?: boolean): void;
  clear(id: string): void;
  pause(): void;
  resume(): void;
  snapshot(id: string): ToastTimerSnapshot | null;
  readonly version: number;
}

export function createToastTimers(deps: {
  onElapsed: (id: string) => void;
  now?: () => number;
  setTimeout?: SetTimeoutFn;
  clearTimeout?: ClearTimeoutFn;
}): ToastTimers {
  const now = deps.now ?? Date.now;
  const setTimeoutFn: SetTimeoutFn = deps.setTimeout ?? ((fn, ms) => setTimeout(fn, ms));
  const clearTimeoutFn: ClearTimeoutFn = deps.clearTimeout ?? ((handle) => clearTimeout(handle));

  const entries = new Map<string, TimerEntry>();
  let version = 0;
  let paused = false;

  function markChanged() {
    version += 1;
  }

  function clear(id: string) {
    const entry = entries.get(id);
    if (!entry) return;
    if (entry.timeout !== undefined) clearTimeoutFn(entry.timeout);
    entries.delete(id);
    markChanged();
  }

  function schedule(id: string, duration: number, deferTimeout = false) {
    const existing = entries.get(id);
    if (existing?.timeout !== undefined) clearTimeoutFn(existing.timeout);
    const entry: TimerEntry = {
      timeout:
        paused || deferTimeout ? undefined : setTimeoutFn(() => deps.onElapsed(id), duration),
      startedAt: now(),
      remaining: duration,
      duration,
    };
    entries.set(id, entry);
    markChanged();
  }

  function pause() {
    let changed = false;
    for (const entry of entries.values()) {
      if (entry.timeout !== undefined) {
        clearTimeoutFn(entry.timeout);
        entry.timeout = undefined;
        changed = true;
      }
      const nextRemaining = Math.max(0, entry.remaining - (now() - entry.startedAt));
      if (nextRemaining !== entry.remaining) changed = true;
      entry.remaining = nextRemaining;
    }
    paused = true;
    if (changed) markChanged();
  }

  function resume() {
    if (!paused) return;
    paused = false;
    for (const [id, entry] of entries) {
      entry.startedAt = now();
      entry.timeout = setTimeoutFn(() => deps.onElapsed(id), entry.remaining);
    }
    if (entries.size > 0) markChanged();
  }

  function snapshot(id: string): ToastTimerSnapshot | null {
    const entry = entries.get(id);
    if (!entry) return null;
    return {
      duration: entry.duration,
      remaining: entry.remaining,
      startedAt: entry.startedAt,
    };
  }

  return {
    schedule,
    clear,
    pause,
    resume,
    snapshot,
    get version() {
      return version;
    },
  };
}

"use client";

import { type CSSProperties, useLayoutEffect, useRef } from "react";
import { cn } from "@/lib/utils";
import { getTimerSnapshot, useToastStore } from "./toast-store";
import { type ToastTone, toastToneBg, toastToneText } from "./toast-variants";

export function CountdownBar({ id, tone }: { id: string; tone: ToastTone }) {
  const fillRef = useRef<HTMLSpanElement | null>(null);
  const rafRef = useRef<number | null>(null);
  const { paused, timerVersion } = useToastStore();

  // biome-ignore lint/correctness/useExhaustiveDependencies: timerVersion is a store revision counter that restarts the countdown animation when timers are recreated.
  useLayoutEffect(() => {
    const fill = fillRef.current;
    if (!fill) return;
    const view = fill.ownerDocument.defaultView ?? globalThis;

    const tick = () => {
      const snap = getTimerSnapshot(id);
      // No timer = persistent toast (error/loading without duration). Park the
      // bar at full and stop the RAF loop instead of churning frames.
      if (!snap || snap.duration <= 0) {
        fill.style.setProperty("--remain", "1");
        rafRef.current = null;
        return;
      }
      const remaining = Math.max(0, snap.remaining - (Date.now() - snap.startedAt));
      const ratio = Math.max(0, Math.min(1, remaining / snap.duration));
      fill.style.setProperty("--remain", String(ratio));
      rafRef.current = view.requestAnimationFrame(tick);
    };

    // While paused the remaining time is frozen, so paint the parked position
    // once and stop the loop instead of re-scheduling an identical frame every
    // tick; unpausing re-runs this effect and resumes the countdown.
    if (paused) {
      const snap = getTimerSnapshot(id);
      const ratio =
        snap && snap.duration > 0 ? Math.max(0, Math.min(1, snap.remaining / snap.duration)) : 1;
      fill.style.setProperty("--remain", String(ratio));
      return;
    }

    rafRef.current = view.requestAnimationFrame(tick);
    return () => {
      if (rafRef.current != null) view.cancelAnimationFrame(rafRef.current);
      rafRef.current = null;
    };
  }, [id, paused, timerVersion]);

  return (
    <div
      data-slot="toast-countdown"
      aria-hidden="true"
      className="relative h-0.5 bg-border/30 overflow-hidden"
    >
      <span
        ref={fillRef}
        className={cn("absolute inset-0 origin-left motion-reduce:hidden", toastToneBg({ tone }))}
        // `--remain` is the registry-facing CSS hook: consumers can override
        // the bar fill via `[data-slot="toast-countdown"] > span { transform:
        // scaleX(...) }` without touching the component. Starts at 1 and the
        // RAF loop updates it in place.
        style={{ "--remain": 1, transform: "scaleX(var(--remain))" } as CSSProperties}
      />
      <ReducedMotionTicks tone={tone} />
    </div>
  );
}

function ReducedMotionTicks({ tone }: { tone: ToastTone }) {
  return (
    <span
      aria-hidden="true"
      className={cn(
        "hidden motion-reduce:flex absolute inset-0 items-center justify-start text-[8px] leading-none tracking-[0.2em] font-mono",
        toastToneText({ tone }),
      )}
    >
      ▰▰▰▱▱
    </span>
  );
}

"use client";

import { useEffect, useRef } from "react";

// Belt-and-braces removal: if onAnimationEnd fails to fire (animation disabled
// via OS settings, forced-colors layer overrides, or the slide token resolved
// to `none` before the reduced-motion fade class loaded), the toast must still
// unmount. Matches the exit-animation budget (slide-out 0.15s + fade-out 0.15s).
const DISMISS_FALLBACK_MS = 200;

/** Provides toast dismiss behavior. */
export function useToastDismiss(dismissing: boolean, id: string, onRemove: (id: string) => void) {
  const removedRef = useRef(false);

  useEffect(() => {
    if (!dismissing) {
      removedRef.current = false;
      return;
    }
    const timer = setTimeout(() => {
      if (!removedRef.current) {
        removedRef.current = true;
        onRemove(id);
      }
    }, DISMISS_FALLBACK_MS);
    return () => clearTimeout(timer);
  }, [dismissing, id, onRemove]);

  return {
    onAnimationEnd: () => {
      if (dismissing && !removedRef.current) {
        removedRef.current = true;
        onRemove(id);
      }
    },
  };
}

"use client";

import { type RefObject, useEffect } from "react";
import { useEscapeKey } from "@/hooks/use-outside-click";
import type { Toast } from "./toast-store";
import { dismiss, pause, resume } from "./toast-store";

function isHovered(node: HTMLElement): boolean {
  try {
    return node.matches(":hover");
  } catch {
    return false;
  }
}

/** Provides toast container behavior. */
export function useToastContainer(
  toasts: Toast[],
  dismissingIds: Set<string>,
  containerRef: RefObject<HTMLElement | null>,
  enabled = true,
) {
  const handleEscape = (event: KeyboardEvent) => {
    const last = toasts.findLast((t) => !dismissingIds.has(t.id));
    if (!last) return;
    // Mark the keypress handled so @diffgazer/keys' window-level dispatch
    // (skip-on-defaultPrevented) does not also run a scope's Escape binding —
    // dismissing a toast must not double-fire navigate/cancel actions, and the
    // region now sits above any open dialog so it must not also close the dialog.
    event.preventDefault();
    dismiss(last.id);
  };

  useEscapeKey(handleEscape, enabled && toasts.length > 0, { priority: 0, ref: containerRef });

  useEffect(() => {
    if (!enabled) return;
    const node = containerRef.current;
    if (!node) return;
    const doc = node.ownerDocument;
    if (node.contains(doc.activeElement)) pause("focus");
    else resume("focus");
    if (isHovered(node)) pause("hover");
    else resume("hover");
    if (doc.hidden) pause("document-hidden");
    else resume("document-hidden");
    function onVisibilityChange() {
      if (doc.hidden) pause("document-hidden");
      else resume("document-hidden");
    }
    doc.addEventListener("visibilitychange", onVisibilityChange);
    return () => {
      doc.removeEventListener("visibilitychange", onVisibilityChange);
      resume("document-hidden");
      resume("focus");
      resume("hover");
    };
  }, [containerRef, enabled]);
}
